# -*- coding: utf-8 -*-
"""
生成测试用 SAP 导出格式 Excel 数据（fixture）
不依赖外部文件，pandas 构造后写入临时 xlsx
"""
import pandas as pd
import os


def build_sample_df() -> pd.DataFrame:
    """构造 10 行有代表性的生产偏差数据（匹配 SAP 导出格式）"""
    return pd.DataFrame({
        '工厂':              ['F1', 'F1',   'F1',  'F1',  'F1',  'F2',  'F2',  'F2',  'F2',  'F2'],
        '工厂名称':          ['达利一厂', '达利一厂', '达利一厂', '达利一厂', '达利一厂',
                         '达利二厂', '达利二厂', '达利二厂', '达利二厂', '达利二厂'],
        '订单日期':          ['2026-05-01'] * 5 + ['2026-05-02'] * 5,
        '订单开始日期':      ['2026-05-01'] * 5 + ['2026-05-02'] * 5,
        '流程订单':          ['PO001', 'PO001', 'PO001', 'PO002', 'PO002',
                         'PO003', 'PO003', 'PO004', 'PO004', 'PO004'],
        '物料编码':          ['MAT-A', 'MAT-B', 'MAT-C', 'MAT-D', 'MAT-E',
                         'MAT-F', 'MAT-G', 'MAT-H', 'MAT-I', 'MAT-J'],
        '组件物料号':        ['MAT-A', 'MAT-B', 'MAT-C', 'MAT-D', 'MAT-E',
                         'MAT-F', 'MAT-G', 'MAT-H', 'MAT-I', 'MAT-J'],
        '组件物料描述':      ['原料A', '原料B', '原料C', '包材D', '包材E',
                         '辅料F', '辅料G', '原料H', '原料I', '包材J'],
        '组件物料类型':      ['Z004', 'Z004', 'Z004', 'Z002', 'Z002',
                         'Z004', 'Z004', 'Z004', 'Z004', 'Z002'],
        '组件物料类型描述':  ['原材料', '原材料', '原材料', '包材', '包材',
                         '原材料', '原材料', '原材料', '原材料', '包材'],
        '组件单位':          ['KG', 'KG', 'KG', '个', '个',
                         'KG', 'KG', 'KG', 'KG', '个'],
        '生产管理员描述':    ['车间一', '车间一', '车间一', '车间一', '车间一',
                         '车间二', '车间二', '车间二', '车间二', '车间二'],
        '数量-定额':         [100, 200, 150,  80, 120,
                          300, 250, 180, 220,  90],
        '数量-实际':         [110, 180, 160,  90,  90,
                          330, 260, 180, 176,  99],
        '偏差率(%)':         [10.0, -10.0, 6.67, 12.5, -25.0,
                          10.0,   4.0,  0.0, -20.0, 10.0],
        '金额-定额(含税)':   [5000, 3000, 4500, 2000, 3600,
                          9000, 5000, 5400, 6600, 2700],
        '金额-实际(含税)':   [5500, 2700, 4800, 2250, 2700,
                          9900, 5200, 5400, 5280, 2970],
        '材料偏差':          [500, -300, 300, 250, -900,
                          900,  200,   0, -1320, 270],
        '备注原因':          ['设备换型', '来料不良', '', '配方调整', '供应商替换',
                         '设备故障', '', '系统无定额', '工艺异常', ''],
    })


def get_expected_summary() -> dict:
    """返回 build_sample_df() 经分析器处理后对应的预期汇总值"""
    return {
        'total_rows': 9,       # 分析器会过滤掉全空备注行
        'pos_dev_rows': 6,     # 正偏差行数
        'neg_dev_rows': 3,     # 负偏差行数
        'zero_dev_rows': 0,    # 零偏差行数（分析器处理后无恰好为0的行）
    }


def create_sample_excel(tmp_dir: str) -> str:
    """生成测试 Excel 文件，返回路径"""
    df = build_sample_df()
    path = os.path.join(tmp_dir, "sample_production_data.xlsx")
    with pd.ExcelWriter(path, engine='openpyxl') as writer:
        df.to_excel(writer, sheet_name='Data', index=False)
    return path
